		.privilege_enable = DT_INST_PROP(n, privilege_enable),                             \
		.irq_config = &ethosu_zephyr_irq_config_##n,                                       \
		.fast_mem_base = ETHOSU_FAST_BASE(n),                                              \
		.fast_mem_size = ETHOSU_FAST_SIZE(n),                                              \
	};                                                                                         \
